--
-- Table structure for table `companies`
--

DROP TABLE IF EXISTS `companies`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `companies` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `cnpj` varchar(18) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `responsible_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `responsible_cpf` varchar(14) COLLATE utf8mb4_unicode_ci NOT NULL,
  `address` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `city` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `state` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `zip_code` varchar(9) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `email` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `subscription_plan_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `vehicle_limit` int NOT NULL DEFAULT '5',
  `subscription_status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `subscription_started_at` datetime(6) DEFAULT CURRENT_TIMESTAMP(6),
  `next_billing_date` date DEFAULT NULL,
  `default_target_consumption` decimal(5,2) DEFAULT '3.50',
  `consumption_alert_threshold` decimal(3,0) DEFAULT '15',
  `asaas_customer_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `asaas_subscription_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `billing_email` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `billing_cpf_cnpj` varchar(18) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `contracted_price_per_vehicle` decimal(10,2) DEFAULT NULL,
  `cte_module_enabled` tinyint(1) NOT NULL DEFAULT '0',
  `cte_monthly_limit` int DEFAULT NULL,
  `coupling_module_enabled` tinyint(1) NOT NULL DEFAULT '0',
  `coupling_asset_limit` int DEFAULT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_companies_cnpj` (`cnpj`),
  UNIQUE KEY `uq_companies_slug` (`slug`),
  KEY `idx_companies_status` (`status`),
  KEY `idx_companies_subscription` (`subscription_plan_id`),
  CONSTRAINT `fk_companies_subscription_plan` FOREIGN KEY (`subscription_plan_id`) REFERENCES `subscription_plans` (`id`) ON DELETE SET NULL,
  CONSTRAINT `companies_subscription_status_check` CHECK ((`subscription_status` in (_utf8mb4'trial',_utf8mb4'active',_utf8mb4'suspended',_utf8mb4'cancelled'))),
  CONSTRAINT `companies_vehicle_limit_check` CHECK ((`vehicle_limit` > 0))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

