--
-- Table structure for table `fuel_expenses`
--

DROP TABLE IF EXISTS `fuel_expenses`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fuel_expenses` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `user_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `company_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `vehicle_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `journey_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `journey_leg_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `gas_station_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `bank_transaction_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `date` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `liters` decimal(10,3) NOT NULL,
  `price_per_liter` decimal(10,4) NOT NULL,
  `total_amount` decimal(12,2) NOT NULL,
  `odometer` int DEFAULT NULL,
  `odometer_final` int DEFAULT NULL,
  `payment_method` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'card',
  `receipt_number` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `receipt_url` text COLLATE utf8mb4_unicode_ci,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `location_lat` decimal(10,6) DEFAULT NULL,
  `location_lng` decimal(10,6) DEFAULT NULL,
  `location_address` text COLLATE utf8mb4_unicode_ci,
  `reconciled_at` datetime(6) DEFAULT NULL,
  `is_ignored` tinyint(1) NOT NULL DEFAULT '0',
  `deleted_at` datetime(6) DEFAULT NULL,
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  PRIMARY KEY (`id`),
  KEY `fk_fuel_expenses_journey_leg` (`journey_leg_id`),
  KEY `fk_fuel_expenses_gas_station` (`gas_station_id`),
  KEY `fk_fuel_expenses_bank_tx` (`bank_transaction_id`),
  KEY `idx_fuel_expenses_company` (`company_id`),
  KEY `idx_fuel_expenses_user_id` (`user_id`),
  KEY `idx_fuel_expenses_vehicle` (`vehicle_id`),
  KEY `idx_fuel_expenses_journey` (`journey_id`),
  KEY `idx_fuel_expenses_date` (`date`),
  KEY `idx_fuel_expenses_reconciled` (`reconciled_at`),
  CONSTRAINT `fk_fuel_expenses_bank_tx` FOREIGN KEY (`bank_transaction_id`) REFERENCES `bank_transactions` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_fuel_expenses_company` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_fuel_expenses_gas_station` FOREIGN KEY (`gas_station_id`) REFERENCES `gas_stations` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_fuel_expenses_journey` FOREIGN KEY (`journey_id`) REFERENCES `journeys` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_fuel_expenses_journey_leg` FOREIGN KEY (`journey_leg_id`) REFERENCES `journey_legs` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_fuel_expenses_vehicle` FOREIGN KEY (`vehicle_id`) REFERENCES `vehicles` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fuel_expenses_payment_method_check` CHECK ((`payment_method` in (_utf8mb4'cash',_utf8mb4'card',_utf8mb4'pix',_utf8mb4'credit',_utf8mb4'tag')))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

