--
-- Table structure for table `journeys`
--

DROP TABLE IF EXISTS `journeys`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `journeys` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `user_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `company_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `vehicle_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `driver_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customer_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `coupling_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `journey_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `origin` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `destination` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `distance` decimal(10,2) DEFAULT NULL,
  `freight_value` decimal(12,2) DEFAULT NULL,
  `commission_percentage` decimal(5,2) NOT NULL DEFAULT '0.00',
  `commission_value` decimal(12,2) NOT NULL DEFAULT '0.00',
  `advance_value` decimal(12,2) NOT NULL DEFAULT '0.00',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'planned',
  `freight_status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `freight_received_date` datetime(6) DEFAULT NULL,
  `freight_due_date` datetime(6) DEFAULT NULL,
  `start_date` datetime(6) DEFAULT NULL,
  `end_date` datetime(6) DEFAULT NULL,
  `start_km` int DEFAULT NULL,
  `end_km` int DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `closure_requested_at` datetime(6) DEFAULT NULL,
  `closure_requested_by` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `closed_at` datetime(6) DEFAULT NULL,
  `closed_by` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `closure_notes` text COLLATE utf8mb4_unicode_ci,
  `start_location_lat` decimal(10,6) DEFAULT NULL,
  `start_location_lng` decimal(10,6) DEFAULT NULL,
  `start_location_address` text COLLATE utf8mb4_unicode_ci,
  `end_location_lat` decimal(10,6) DEFAULT NULL,
  `end_location_lng` decimal(10,6) DEFAULT NULL,
  `end_location_address` text COLLATE utf8mb4_unicode_ci,
  `created_by_driver` tinyint(1) NOT NULL DEFAULT '0',
  `deleted_at` datetime(6) DEFAULT NULL,
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  PRIMARY KEY (`id`),
  KEY `idx_journeys_user_id` (`user_id`),
  KEY `idx_journeys_company` (`company_id`),
  KEY `idx_journeys_vehicle` (`vehicle_id`),
  KEY `idx_journeys_driver` (`driver_id`),
  KEY `idx_journeys_status` (`status`),
  KEY `idx_journeys_customer` (`customer_id`),
  KEY `idx_journeys_coupling` (`coupling_id`),
  KEY `idx_journeys_deleted_at` (`deleted_at`),
  CONSTRAINT `fk_journeys_company` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_journeys_coupling` FOREIGN KEY (`coupling_id`) REFERENCES `vehicle_couplings` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_journeys_customer` FOREIGN KEY (`customer_id`) REFERENCES `parties` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_journeys_driver` FOREIGN KEY (`driver_id`) REFERENCES `drivers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_journeys_vehicle` FOREIGN KEY (`vehicle_id`) REFERENCES `vehicles` (`id`) ON DELETE CASCADE,
  CONSTRAINT `journeys_freight_status_check` CHECK ((`freight_status` in (_utf8mb4'pending',_utf8mb4'received',_utf8mb4'invoiced'))),
  CONSTRAINT `journeys_status_check` CHECK ((`status` in (_utf8mb4'planned',_utf8mb4'in_progress',_utf8mb4'completed',_utf8mb4'cancelled',_utf8mb4'pending_approval')))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

