--
-- Table structure for table `revenue`
--

DROP TABLE IF EXISTS `revenue`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `revenue` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `user_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `company_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `journey_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `journey_leg_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `category_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `bank_transaction_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customer_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `amount` decimal(12,2) NOT NULL,
  `date` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `payment_method` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'bank_transfer',
  `category` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'carga',
  `client` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `invoice_number` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'received',
  `reconciled_at` datetime(6) DEFAULT NULL,
  `deleted_at` datetime(6) DEFAULT NULL,
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  `account_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Conta de destino da receita',
  PRIMARY KEY (`id`),
  KEY `fk_revenue_journey_leg` (`journey_leg_id`),
  KEY `fk_revenue_category` (`category_id`),
  KEY `fk_revenue_bank_tx` (`bank_transaction_id`),
  KEY `idx_revenue_company` (`company_id`),
  KEY `idx_revenue_user_id` (`user_id`),
  KEY `idx_revenue_journey` (`journey_id`),
  KEY `idx_revenue_status` (`status`),
  KEY `idx_revenue_reconciled` (`reconciled_at`),
  KEY `idx_revenue_customer` (`customer_id`),
  KEY `idx_revenue_deleted_at` (`deleted_at`),
  KEY `fk_revenue_account` (`account_id`),
  CONSTRAINT `fk_revenue_account` FOREIGN KEY (`account_id`) REFERENCES `financial_accounts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_revenue_bank_tx` FOREIGN KEY (`bank_transaction_id`) REFERENCES `bank_transactions` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_revenue_category` FOREIGN KEY (`category_id`) REFERENCES `revenue_categories` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_revenue_company` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_revenue_customer` FOREIGN KEY (`customer_id`) REFERENCES `parties` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_revenue_journey` FOREIGN KEY (`journey_id`) REFERENCES `journeys` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_revenue_journey_leg` FOREIGN KEY (`journey_leg_id`) REFERENCES `journey_legs` (`id`) ON DELETE SET NULL,
  CONSTRAINT `revenue_payment_method_check` CHECK ((`payment_method` in (_utf8mb4'cash',_utf8mb4'card',_utf8mb4'pix',_utf8mb4'bank_transfer',_utf8mb4'check',_utf8mb4'tag'))),
  CONSTRAINT `revenue_status_check` CHECK ((`status` in (_utf8mb4'pending',_utf8mb4'received',_utf8mb4'cancelled')))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

