--
-- Table structure for table `vehicles`
--

DROP TABLE IF EXISTS `vehicles`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vehicles` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `user_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `company_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `plate` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `model` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `brand` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `year` int DEFAULT NULL,
  `chassis` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `renavam` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fuel_type` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'diesel',
  `tank_capacity` decimal(10,2) DEFAULT NULL,
  `avg_consumption` decimal(5,2) DEFAULT NULL,
  `target_consumption` decimal(5,2) DEFAULT NULL,
  `actual_consumption` decimal(5,2) DEFAULT NULL,
  `consumption_last_updated` datetime(6) DEFAULT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `purchase_date` date DEFAULT NULL,
  `purchase_value` decimal(12,2) DEFAULT NULL,
  `current_value` decimal(12,2) DEFAULT NULL,
  `insurance_company` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `insurance_policy` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `insurance_expiry` date DEFAULT NULL,
  `vehicle_type` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT 'truck',
  `trailer_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `axle_count` int DEFAULT NULL,
  `load_capacity` decimal(12,2) DEFAULT NULL,
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  PRIMARY KEY (`id`),
  KEY `idx_vehicles_user_id` (`user_id`),
  KEY `idx_vehicles_company` (`company_id`),
  KEY `idx_vehicles_status` (`status`),
  KEY `idx_vehicles_type` (`vehicle_type`),
  KEY `idx_vehicles_company_type` (`company_id`,`vehicle_type`),
  CONSTRAINT `fk_vehicles_company` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE SET NULL,
  CONSTRAINT `vehicles_fuel_type_check` CHECK ((`fuel_type` in (_utf8mb4'diesel',_utf8mb4'gasoline',_utf8mb4'ethanol',_utf8mb4'hybrid',_utf8mb4'electric'))),
  CONSTRAINT `vehicles_status_check` CHECK ((`status` in (_utf8mb4'active',_utf8mb4'inactive',_utf8mb4'maintenance',_utf8mb4'sold')))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

